    10→  <link rel="stylesheet" href="/css/styles.css">
    11→  <style>
    12→    * {
    13→      margin: 0;
    14→      padding: 0;
    15→      box-sizing: border-box;
    16→    }
    17→
    18→    body {
    19→      font-family: 'Inter', sans-serif;
    20→      background: linear-gradient(135deg, #1e293b 0%, #334155 100%);
    21→      min-height: 100vh;
    22→      color: white;
    23→    }
    24→
    25→    .container {
    26→      max-width: 1200px;
    27→      margin: 0 auto;
    28→      padding: 2rem;
    29→    }
    30→
    31→    .header {
    32→      text-align: center;
    33→      margin-bottom: 2rem;
    34→    }
    35→
