    58→      border-radius: 24px;
    59→      padding: 3rem;
    60→      color: #1e293b;
    61→      box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    62→    }
    63→
    64→    /* Question Display */
    65→    .question-section {
    66→      text-align: center;
    67→      margin-bottom: 2rem;
    68→    }
    69→
    70→    .question-number {
    71→      font-size: 0.875rem;
    72→      font-weight: 600;
    73→      color: #64748b;
    74→      margin-bottom: 1rem;
    75→    }
    76→
    77→    .question-text {
    78→      font-family: 'Space Grotesk', sans-serif;
    79→      font-size: 1.75rem;
    80→      font-weight: 600;
    81→      color: #1e293b;
    82→      margin-bottom: 1rem;
    83→      line-height: 1.4;
    84→    }
    85→
