   523→  <script src="/js/main.js"></script>
   524→  <script>
   525→    let mediaStream = null;
   526→    let mediaRecorder = null;
   527→    let recordedChunks = [];
   528→    let currentQuestionIndex = 0;
   529→    let questions = [];
   530→    let responses = [];
   531→    let interviewId = null;
   532→    let timerInterval = null;
   533→    let timeRemaining = 120; // 2 minutes in seconds
   534→    let retakesUsed = {};
   535→
   536→    // Initialize
   537→    document.addEventListener('DOMContentLoaded', async () => {
   538→      const user = await checkAuth();
   539→      if (!user) {
   540→        window.location.href = '/login.html';
   541→        return;
   542→      }
   543→
   544→      // Get interview ID from URL or create new
   545→      const urlParams = new URLSearchParams(window.location.search);
   546→      const jobId = urlParams.get('job_id');
   547→
   548→      // Request camera access for preview
   549→      try {
   550→        mediaStream = await navigator.mediaDevices.getUserMedia({
   551→          video: { width: 1280, height: 720 },
   552→          audio: true
   553→        });
   554→        document.getElementById('preview-video').srcObject = mediaStream;
   555→        document.getElementById('preview-overlay').style.display = 'none';
   556→      } catch (err) {
   557→        console.error('Camera access error:', err);
   558→        alert('Camera access is required for video interviews. Please allow permissions and reload.');
   559→      }
   560→    });
   561→
   562→    async function startInterview() {
   563→      try {
   564→        // Create interview session
   565→        const result = await apiCall('/interviews/start', {
   566→          method: 'POST',
   567→          body: JSON.stringify({
   568→            interview_type: 'video',
   569→            job_title: 'Software Developer', // TODO: Get from URL params or selection
   570→            job_description: 'General software development role'
   571→          })
   572→        });
   573→
   574→        if (!result.success) {
   575→          throw new Error('Failed to start interview');
   576→        }
   577→
   578→        interviewId = result.interview.id;
   579→        questions = result.questions;
   580→        responses = new Array(questions.length).fill(null);
   581→
   582→        // Update UI
   583→        updateProgress();
   584→        showState('recording');
   585→        displayQuestion(0);
   586→      } catch (err) {
   587→        console.error('Start interview error:', err);
   588→        alert('Failed to start interview. Please try again.');
   589→      }
   590→    }
   591→
   592→    function displayQuestion(index) {
   593→      currentQuestionIndex = index;
   594→      const question = questions[index];
   595→
   596→      document.getElementById('question-number').textContent = `Question ${index + 1} of ${questions.length}`;
   597→      document.getElementById('question-text').textContent = question.question;
   598→
   599→      // Reset timer
   600→      timeRemaining = 120;
   601→      updateTimer();
   602→
   603→      // Update progress
   604→      updateProgress();
   605→
   606→      // Setup video for recording
   607→      if (mediaStream) {
   608→        document.getElementById('recording-video').srcObject = mediaStream;
   609→      }
   610→    }
   611→
   612→    function startRecording() {
   613→      recordedChunks = [];
   614→
   615→      try {
   616→        mediaRecorder = new MediaRecorder(mediaStream, {
   617→          mimeType: 'video/webm;codecs=vp9'
   618→        });
   619→
   620→        mediaRecorder.ondataavailable = (event) => {
   621→          if (event.data.size > 0) {
   622→            recordedChunks.push(event.data);
   623→          }
   624→        };
   625→
   626→        mediaRecorder.onstop = handleRecordingStop;
   627→
   628→        mediaRecorder.start();
   629→
   630→        // Update UI
   631→        document.getElementById('record-btn').style.display = 'none';
   632→        document.getElementById('stop-btn').style.display = 'inline-flex';
   633→        document.getElementById('recording-indicator').classList.add('active');
   634→
   635→        // Start timer
   636→        timerInterval = setInterval(() => {
   637→          timeRemaining--;
   638→          updateTimer();
   639→
   640→          if (timeRemaining <= 0) {
   641→            stopRecording();
   642→          }
   643→        }, 1000);
   644→      } catch (err) {
   645→        console.error('Recording error:', err);
   646→        alert('Failed to start recording. Please try again.');
   647→      }
   648→    }
   649→
   650→    function stopRecording() {
   651→      if (mediaRecorder && mediaRecorder.state !== 'inactive') {
   652→        mediaRecorder.stop();
   653→        clearInterval(timerInterval);
   654→
   655→        // Update UI
   656→        document.getElementById('record-btn').style.display = 'inline-flex';
   657→        document.getElementById('stop-btn').style.display = 'none';
   658→        document.getElementById('recording-indicator').classList.remove('active');
   659→      }
   660→    }
   661→
   662→    function handleRecordingStop() {
   663→      const blob = new Blob(recordedChunks, { type: 'video/webm' });
   664→      const videoUrl = URL.createObjectURL(blob);
   665→
   666→      // Show review state
   667→      document.getElementById('review-question-number').textContent =
   668→        `Question ${currentQuestionIndex + 1} of ${questions.length}`;
   669→      document.getElementById('review-question-text').textContent = questions[currentQuestionIndex].question;
   670→
   671→      const playbackVideo = document.getElementById('playback-video');
   672→      playbackVideo.src = videoUrl;
   673→
   674→      // Update retake button
   675→      const retakeBtn = document.getElementById('retake-btn');
   676→      const retakesForQuestion = retakesUsed[currentQuestionIndex] || 0;
   677→      if (retakesForQuestion >= 1) {
   678→        retakeBtn.disabled = true;
   679→        retakeBtn.textContent = '🔄 No retakes remaining';
   680→      } else {
   681→        retakeBtn.disabled = false;
   682→        retakeBtn.textContent = `🔄 Retake (${1 - retakesForQuestion} remaining)`;
   683→      }
   684→
   685→      showState('review');
   686→
   687→      // Store the blob temporarily
   688→      window.currentRecordingBlob = blob;
   689→    }
   690→
   691→    function retakeResponse() {
   692→      const retakesForQuestion = retakesUsed[currentQuestionIndex] || 0;
   693→      if (retakesForQuestion >= 1) {
   694→        alert('No retakes remaining for this question.');
   695→        return;
   696→      }
   697→
   698→      retakesUsed[currentQuestionIndex] = retakesForQuestion + 1;
   699→      showState('recording');
   700→      displayQuestion(currentQuestionIndex);
   701→    }
   702→
   703→    async function acceptResponse() {
   704→      // Show loading
   705→      document.getElementById('submit-btn').disabled = true;
   706→      document.getElementById('submit-btn').innerHTML = '<span class="loading-spinner"></span> Uploading...';
   707→
   708→      try {
   709→        // Upload video
   710→        const videoUrl = await uploadVideo(window.currentRecordingBlob, currentQuestionIndex);
   711→
   712→        // Save response
   713→        responses[currentQuestionIndex] = {
   714→          question_index: currentQuestionIndex,
   715→          video_url: videoUrl,
   716→          response_text: '[Video response]',
   717→          recorded_at: new Date().toISOString()
   718→        };
   719→
   720→        // Move to next question or complete
   721→        if (currentQuestionIndex < questions.length - 1) {
   722→          showState('recording');
   723→          displayQuestion(currentQuestionIndex + 1);
   724→        } else {
   725→          showCompleteState();
   726→        }
   727→      } catch (err) {
   728→        console.error('Upload error:', err);
   729→        alert('Failed to upload video. Please try again.');
   730→      } finally {
   731→        document.getElementById('submit-btn').disabled = false;
   732→        document.getElementById('submit-btn').innerHTML = 'Submit Interview';
   733→      }
   734→    }
   735→
   736→    async function uploadVideo(blob, questionIndex) {
   737→      const formData = new FormData();
   738→      formData.append('video', blob, `interview-${interviewId}-q${questionIndex}.webm`);
   739→      formData.append('interview_id', interviewId);
   740→      formData.append('question_index', questionIndex);
   741→
   742→      const response = await apiCall('/interviews/upload-video', {
   743→        method: 'POST',
   744→        body: formData,
   745→        isFormData: true
   746→      });
   747→
   748→      if (!response.success) {
   749→        throw new Error(response.error || 'Upload failed');
   750→      }
   751→
   752→      return response.video_url;
   753→    }
   754→
   755→    function showCompleteState() {
   756→      // Build responses list
   757→      const responsesList = document.getElementById('responses-list');
   758→      responsesList.innerHTML = responses.map((r, i) => `
   759→        <div class="response-item">
   760→          <div class="response-number">${i + 1}</div>
   761→          <div style="flex: 1;">
   762→            <div style="font-weight: 600; margin-bottom: 0.25rem;">${questions[i].question}</div>
   763→            <div class="response-status completed">✓ Video recorded</div>
   764→          </div>
   765→        </div>
   766→      `).join('');
   767→
   768→      showState('complete');
   769→    }
   770→
   771→    async function submitInterview() {
   772→      document.getElementById('submit-btn').disabled = true;
   773→      document.getElementById('submit-btn').innerHTML = '<span class="loading-spinner"></span> Submitting...';
   774→
   775→      try {
   776→        // Submit all responses
   777→        for (let i = 0; i < responses.length; i++) {
   778→          if (responses[i]) {
   779→            await apiCall(`/interviews/${interviewId}/respond`, {
   780→              method: 'POST',
   781→              body: JSON.stringify(responses[i])
   782→            });
   783→          }
   784→        }
   785→
   786→        // Complete interview
   787→        await apiCall(`/interviews/${interviewId}/complete`, {
   788→          method: 'POST'
   789→        });
   790→
   791→        // Stop media stream
   792→        if (mediaStream) {
   793→          mediaStream.getTracks().forEach(track => track.stop());
   794→        }
   795→
   796→        // Redirect to results
   797→        alert('Interview submitted successfully!');
   798→        window.location.href = `/history.html?interview_id=${interviewId}`;
   799→      } catch (err) {
   800→        console.error('Submit error:', err);
   801→        alert('Failed to submit interview. Please try again.');
   802→        document.getElementById('submit-btn').disabled = false;
   803→        document.getElementById('submit-btn').innerHTML = 'Submit Interview';
   804→      }
   805→    }
   806→
   807→    function showState(state) {
   808→      document.querySelectorAll('.setup-state, .recording-state, .review-state, .complete-state')
   809→        .forEach(el => el.classList.remove('active'));
   810→
   811→      if (state === 'recording') {
   812→        document.getElementById('recording-state').classList.add('active');
   813→      } else if (state === 'review') {
   814→        document.getElementById('review-state').classList.add('active');
   815→      } else if (state === 'complete') {
   816→        document.getElementById('complete-state').classList.add('active');
   817→      }
   818→    }
   819→
   820→    function updateProgress() {
   821→      const completed = responses.filter(r => r !== null).length;
   822→      const total = questions.length;
   823→      const percent = total > 0 ? (completed / total) * 100 : 0;
   824→
   825→      document.getElementById('progress-fill').style.width = `${percent}%`;
   826→      document.getElementById('progress-text').textContent = `Question ${completed} of ${total}`;
   827→    }
   828→
   829→    function updateTimer() {
   830→      const minutes = Math.floor(timeRemaining / 60);
   831→      const seconds = timeRemaining % 60;
   832→      const timerEl = document.getElementById('timer');
   833→
   834→      timerEl.textContent = `${minutes}:${seconds.toString().padStart(2, '0')}`;
   835→
   836→      if (timeRemaining <= 10) {
   837→        timerEl.classList.add('critical');
   838→      } else if (timeRemaining <= 30) {
   839→        timerEl.classList.add('warning');
   840→      } else {
   841→        timerEl.classList.remove('warning', 'critical');
   842→      }
   843→    }
   844→
   845→    // Cleanup on page unload
   846→    window.addEventListener('beforeunload', () => {
   847→      if (mediaStream) {
   848→        mediaStream.getTracks().forEach(track => track.stop());
   849→      }
   850→    });
   851→  </script>
