.recording-indicator.active {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

/* Live Analysis Overlay */
.analysis-overlay {
  display: none;
  position: absolute;
  bottom: 1rem;
  left: 1rem;
  right: 1rem;
  background: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(10px);
  border-radius: 12px;
  padding: 1rem;
  color: white;
  z-index: 10;
}

.analysis-overlay.active {
  display: block;
}

.analysis-toggle {
  position: absolute;
  top: 1rem;
  left: 1rem;
  background: rgba(0, 0, 0, 0.7);
  color: white;
  border: none;
  padding: 0.5rem 1rem;
  border-radius: 8px;
  font-size: 0.875rem;
  cursor: pointer;
  z-index: 11;
  transition: all 0.3s ease;
}

.analysis-toggle:hover {
  background: rgba(0, 0, 0, 0.9);
}

.analysis-metrics {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
  gap: 1rem;
}

.metric-item {
  text-align: center;
}

.metric-value {
  font-size: 2rem;
  font-weight: 700;
  display: block;
  margin-bottom: 0.25rem;
}

.metric-label {
  font-size: 0.75rem;
  opacity: 0.8;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.metric-good { color: #10b981; }
.metric-warning { color: #f59e0b; }
.metric-poor { color: #ef4444; }

